+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+type WindowValue<T extends SQLWrapper> = T extends SQL<infer TValue> ? TValue
+	: T extends AnyColumn ? T['_']['data']
+	: unknown;
+
+export type WindowBoundary =
+	| { type: 'unbounded preceding' | 'current row' | 'unbounded following' }
+	| { type: 'preceding' | 'following'; value: number };
+
+export const unboundedPreceding: WindowBoundary = { type: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { type: 'current row' };
+export const unboundedFollowing: WindowBoundary = { type: 'unbounded following' };
+
+function position(value: number, helper: string): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${helper}() requires a non-negative integer, received ${value}`);
+	}
+	return { type: helper, value } as WindowBoundary;
+}
+
+export function preceding(value: number): WindowBoundary {
+	return position(value, 'preceding');
+}
+
+export function following(value: number): WindowBoundary {
+	return position(value, 'following');
+}
+
+export interface WindowFrameSpec {
+	from: WindowBoundary;
+	to: WindowBoundary;
+}
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly spec: WindowFrameSpec;
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	switch (boundary.type) {
+		case 'unbounded preceding': return Number.NEGATIVE_INFINITY;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Number.POSITIVE_INFINITY;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: WindowFrameSpec): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, spec };
+}
+
+export function rows(spec: WindowFrameSpec): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: WindowFrameSpec): WindowFrame {
+	return frame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	return 'value' in boundary
+		? sql`${sql.raw(String(boundary.value))} ${sql.raw(boundary.type)}`
+		: sql.raw(boundary.type);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const clauses: SQL[] = [];
+	if (spec.partitionBy) {
+		const partitionBy = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+		clauses.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		const orderBy = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+		clauses.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	}
+	if (spec.frame) {
+		clauses.push(sql`${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.spec.from)} and ${boundarySql(spec.frame.spec.to)}`);
+	}
+	return sql.join(clauses, sql` `);
+}
+
+export class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(name: string, ...args: SQLWrapper[]): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positiveInteger(value: number, helper: string): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${helper}() requires a positive integer, received ${value}`);
+	}
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> {
+	positiveInteger(buckets, 'ntile');
+	return new WindowFunction(sql`ntile(${sql.raw(String(buckets))})`);
+}
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number, defaultValue: SQLWrapper): WindowFunction<Exclude<WindowValue<T>, null>>;
+export function lag(expression: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	const args = [expression, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])];
+	return windowFunction('lag', ...args);
+}
+
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number, defaultValue: SQLWrapper): WindowFunction<Exclude<WindowValue<T>, null>>;
+export function lead(expression: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	const args = [expression, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])];
+	return windowFunction('lead', ...args);
+}
+
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null> { return windowFunction('first_value', expression); }
